/**
 * Notification model and related types.
 *
 * These types define the notification system's data structures.
 * All notification adapters and the NotificationService operate on these types.
 */

/**
 * Supported notification channels. Each channel has a corresponding adapter
 * that implements the NotificationAdapter interface.
 */
export type NotificationChannel = 'email' | 'webhook' | 'in-app' | 'sms';

/**
 * Categories of notifications. Used by adapters to determine formatting
 * and priority handling.
 */
export type NotificationType =
  | 'order-confirmation'
  | 'order-status-update'
  | 'welcome'
  | 'account-update'
  | 'system-alert';

/**
 * The payload passed to notification adapters for delivery.
 * Adapters receive this and format/send it according to their channel.
 */
export interface NotificationPayload {
  recipient: string;
  subject: string;
  body: string;
  type: NotificationType;
  channel: NotificationChannel;
  metadata?: Record<string, unknown>;
}

/**
 * A sent notification record, stored by the NotificationService.
 */
export interface Notification {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  type: NotificationType;
  channel: NotificationChannel;
  status: 'sent' | 'failed';
  sentAt: Date;
  metadata?: Record<string, unknown>;
}

/**
 * Base interface for all notification adapters.
 *
 * CONSTRAINT: Every notification channel (email, webhook, SMS, in-app, etc.)
 * MUST implement this interface. The NotificationService dispatches to adapters
 * based on the channel field in the NotificationPayload.
 *
 * Adapters are responsible for:
 * - Formatting the notification for their specific channel
 * - Delivering the notification (or stubbing delivery in dev/test)
 * - Reporting success or failure via the returned result
 */

import type { NotificationChannel, NotificationPayload } from '../models/notification.js';

/**
 * Result returned by an adapter after attempting to send a notification.
 */
export interface NotificationResult {
  success: boolean;
  channel: NotificationChannel;
  error?: string;
}

/**
 * All notification adapters must implement this interface.
 */
export interface NotificationAdapter {
  /**
   * The channel this adapter handles. Used by NotificationService
   * to route payloads to the correct adapter.
   */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this adapter's channel.
   * Must not throw — return a failed NotificationResult instead.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter.
 *
 * Implements NotificationAdapter for the 'email' channel.
 * Currently a stub that logs emails rather than sending them.
 * Replace the send() implementation with a real email provider
 * (e.g., SendGrid, SES, SMTP) for production use.
 */

import type { NotificationAdapter, NotificationResult } from './notification.adapter.js';
import type { NotificationPayload } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');

  /**
   * Send an email notification.
   *
   * Stub implementation: logs the email and returns success.
   * Production implementation should integrate with an email provider.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(
      `Email to ${payload.recipient}: [${payload.subject}] ${payload.body}`,
    );

    return {
      success: true,
      channel: 'email',
    };
  }
}
